class Solution:
    def largestPalindromic(self, num):
        from collections import Counter
        cnt = Counter(num)
        # leading half: digits 9..0 each repeated cnt//2 times, kept as a list of chars
        left = []
        for d in '9876543210':
            left.extend(d * (cnt[d] // 2))
        # strip leading '0' chars from the half (they would be leading zeros)
        i = 0
        while i < len(left) and left[i] == '0':
            i += 1
        left = left[i:]
        # middle: largest odd-count digit
        mid = ''
        for d in '9876543210':
            if cnt[d] % 2 == 1:
                mid = d
                break
        if not left:
            return mid if mid else '0'
        head = ''.join(left)
        return head + mid + head[::-1]

