class Solution:
    def largestPalindromic(self, num):
        cnt = [0] * 10
        for ch in num:
            cnt[ord(ch) - 48] += 1
        half_parts = []
        for d in range(9, 0, -1):
            half_parts.append(str(d) * (cnt[d] // 2))
        head = ''.join(half_parts)
        if head:
            head += '0' * (cnt[0] // 2)
        mid = ''
        for d in range(9, -1, -1):
            if cnt[d] % 2 == 1:
                mid = str(d)
                break
        if not head:
            return mid if mid else '0'
        return head + mid + head[::-1]

