var largestPalindromic = function(num) {
    const cnt = new Array(10).fill(0);
    for (const ch of num) cnt[ch.charCodeAt(0) - 48]++;
    const parts = [];
    for (let d = 9; d >= 1; d--) parts.push(String(d).repeat(Math.floor(cnt[d] / 2)));
    let head = parts.join('');
    if (head) head += '0'.repeat(Math.floor(cnt[0] / 2));
    let mid = '';
    for (let d = 9; d >= 0; d--) {
        if (cnt[d] % 2 === 1) { mid = String(d); break; }
    }
    if (!head) return mid ? mid : '0';
    return head + mid + head.split('').reverse().join('');
};
